/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    CustInvoiceJour      custInvJour;
    RefRecId             agreementHeaderRecId;
    String30             contractNum;
    DimensionDefault     defaultDimRecId;
    ETGACFParameters     etgACFParameters;
    SalesLine            salesLine;
    SalesTable           salesTable;

    if(ETGACFParameters::find().EnableGRMReportChanges == NoYes::No)
    {
        throw Error("GMR report feature is not enabled");
    }

    changecompany("o001")
    {
        ttsbegin;

        etgACFParameters = ETGACFParameters::find();

        while select forupdate custInvJour
            where custInvJour.DataAreaId == "o001"
            && custInvJour.SalesId != ""
        {
            salesTable           = SalesTable::find(custInvJour.SalesId);
            defaultDimRecId      = salesTable.DefaultDimension;
            contractNum          = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(defaultDimRecId, etgACFParameters.Contract);

            if(!contractNum)
            {
                select firstonly DefaultDimension from salesLine where salesLine.SalesId == salesTable.SalesId;
                defaultDimRecId      = salesTable.DefaultDimension;
                contractNum          = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(defaultDimRecId, etgACFParameters.Contract);
            }

            if(contractNum)
            {
                custInvJour.skipDataMethods(true);
                custInvJour.ETGContractNum = contractNum;
                custInvJour.doUpdate();
                Info(strFmt("Invoice Id %1 contract number - %2 updated", custInvJour.InvoiceId, contractNum));
            }
        }

        ttscommit;
    }
}
